challenge.solution:
export default function App() {
  const items = [
    { title: 'Componentes', desc: 'Aprenda a criar componentes reutilizáveis' },
    { title: 'Hooks', desc: 'Domine useState, useEffect e mais' },
    { title: 'Rotas', desc: 'Navegação com React Router' },
  ];

  return (
    <div className="space-y-3 p-8">
      {items.map((item) => (
        <div
          key={item.title}
          className="group flex cursor-pointer items-center justify-between rounded-lg border border-gray-200 p-4 shadow-sm transition-all duration-200 hover:-translate-y-1 hover:border-blue-500 hover:shadow-md"
        >
          <div>
            <h3 className="font-semibold text-gray-900">{item.title}</h3>
            <p className="text-sm text-gray-500">{item.desc}</p>
          </div>
          <span className="text-gray-400 transition-colors group-hover:text-blue-500">
            →
          </span>
        </div>
      ))}
    </div>
  );
}
